#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
int n,a[N],l[N],r[N],root;stack<int> st;
void DFS(int u){if(!u)return;cout<<u<<" ";DFS(l[u]);DFS(r[u]);}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){int x;cin>>x;a[x]=i;}
    for(int i=1;i<=n;i++){
        while(!st.empty()&&a[i]<a[st.top()])l[i]=st.top(),st.pop();
        r[(!st.empty()?st.top():0)]=i;st.push(i);
    }
    while(!st.empty())root=st.top(),st.pop();DFS(root);
    return 0;
}
